const pendingRows = $('Read Pending Count').all ? $('Read Pending Count').all() : [];
const pendingCount = pendingRows.filter(r => r.json && r.json.conversation_id).length;
const rows = $input.all().map(item => item.json);
const today = new Date().toISOString().split('T')[0];
const filteredRows = rows;
const counts = { Critical: 0, High: 0, Medium: 0, Low: 0 };
const categoryMap = {};
const criticalHighItems = [];
const agentScores = {};
for (const row of filteredRows) {
  const severity = row.severity || row[4] || 'Low';
  const category = row.issue_category || row[5] || 'Other';
  const agentName = row.agent_name || row[2] || 'Unknown';
  const agentScore = parseInt(row.agent_score || row[8] || 3, 10);
  const convId = row.conversation_id || row[0];
  const summary = row.summary || row[3] || '';
  const recommendedAction = row.recommended_action || row[10] || '';
  const intercomLink = row.intercom_link || row[14] || '';
  if (counts.hasOwnProperty(severity)) counts[severity]++;
  categoryMap[category] = (categoryMap[category] || 0) + 1;
  if (severity === 'Critical' || severity === 'High') criticalHighItems.push({ conversation_id: convId, agent_name: agentName, issue_category: category, severity, summary, recommended_action: recommendedAction, intercom_link: intercomLink });
  if (!agentScores[agentName]) agentScores[agentName] = { total: 0, count: 0 };
  agentScores[agentName].total += agentScore;
  agentScores[agentName].count++;
}
const total = filteredRows.length;
const satisfactionRate = total > 0 ? Math.round((counts.Low / total) * 1000) / 10 : 0;
const topIssues = Object.entries(categoryMap).sort((a, b) => b[1] - a[1]).slice(0, 5).map(([category, count]) => ({ category, count }));
const agentFlags = Object.entries(agentScores).map(([name, data]) => ({ agent_name: name, avg_score: Math.round((data.total / data.count) * 10) / 10, conversation_count: data.count })).filter(a => a.avg_score <= 2).sort((a, b) => a.avg_score - b.avg_score);
return [{ json: { date: today, total_analyzed: total, pending_analysis_count: pendingCount, critical_count: counts.Critical, high_count: counts.High, medium_count: counts.Medium, low_count: counts.Low, satisfaction_rate: satisfactionRate, top_issues: topIssues, critical_high_items: criticalHighItems, agent_flags: agentFlags, generated_at: new Date().toISOString() } }];

const m = $input.first().json;
const pendingBanner = m.pending_analysis_count > 0 ? `<tr><td style="background:#fef3c7;padding:12px 28px;border-left:4px solid #d97706"><p style="margin:0;color:#92400e;font-size:13px">⚠️ <strong>${m.pending_analysis_count} conversations still pending analysis</strong> — this report may be incomplete. Final numbers will be available once analysis completes.</p></td></tr>` : '';
const satColor = m.satisfaction_rate >= 80 ? '#16a34a' : m.satisfaction_rate >= 60 ? '#d97706' : '#dc2626';
const critHighRows = m.critical_high_items.slice(0, 20).map(i => `<tr style="border-bottom:1px solid #e5e7eb"><td style="padding:8px 10px;font-family:monospace;font-size:12px">${i.conversation_id}</td><td style="padding:8px 10px;font-size:13px">${i.agent_name}</td><td style="padding:8px 10px;font-size:13px">${i.issue_category}</td><td style="padding:8px 10px;font-size:12px;font-weight:bold;color:${i.severity==='Critical'?'#dc2626':'#ea580c'}">${i.severity}</td><td style="padding:8px 10px;font-size:12px;color:#4b5563">${i.recommended_action}</td><td style="padding:8px 10px"><a href="${i.intercom_link}" style="color:#2563eb;font-size:12px">View</a></td></tr>`).join('');
const topRows = m.top_issues.map((i, idx) => `<tr style="background:${idx%2===0?'#fff':'#f9fafb'}"><td style="padding:8px 10px;font-weight:bold">#${idx+1}</td><td style="padding:8px 10px">${i.category}</td><td style="padding:8px 10px;text-align:center;font-weight:bold">${i.count}</td></tr>`).join('');
const flagRows = m.agent_flags.length > 0 ? m.agent_flags.map(a => `<tr style="background:#fef2f2"><td style="padding:8px 10px">${a.agent_name}</td><td style="padding:8px 10px;text-align:center;color:#dc2626;font-weight:bold">${a.avg_score}</td><td style="padding:8px 10px;text-align:center">${a.conversation_count}</td></tr>`).join('') : '<tr><td colspan="3" style="padding:12px;text-align:center;color:#6b7280;font-style:italic">No agent flags today</td></tr>';
const html = `<!DOCTYPE html><html><body style="margin:0;padding:0;background:#f3f4f6;font-family:Arial,sans-serif"><table width="100%" cellpadding="0" cellspacing="0" style="background:#f3f4f6;padding:20px 0"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0">${pendingBanner}<tr><td style="background:#1a1a2e;padding:24px 28px;border-radius:8px 8px 0 0"><h1 style="margin:0;color:#fff;font-size:20px">Daily Chat QA Report</h1><p style="margin:6px 0 0;color:#94a3b8;font-size:14px">${m.date}</p></td></tr><tr><td style="background:#fff;padding:20px 28px"><table width="100%"><tr><td width="25%" style="text-align:center;padding:12px 6px"><div style="font-size:32px;font-weight:bold;color:#1a1a2e">${m.total_analyzed}</div><div style="font-size:12px;color:#6b7280">Total</div></td><td width="25%" style="text-align:center;padding:12px 6px;border-left:1px solid #e5e7eb"><div style="font-size:32px;font-weight:bold;color:${satColor}">${m.satisfaction_rate}%</div><div style="font-size:12px;color:#6b7280">Satisfaction</div></td><td width="25%" style="text-align:center;padding:12px 6px;border-left:1px solid #e5e7eb"><div style="font-size:32px;font-weight:bold;color:#dc2626">${m.critical_count}</div><div style="font-size:12px;color:#6b7280">Critical</div></td><td width="25%" style="text-align:center;padding:12px 6px;border-left:1px solid #e5e7eb"><div style="font-size:32px;font-weight:bold;color:#ea580c">${m.high_count}</div><div style="font-size:12px;color:#6b7280">High</div></td></tr></table></td></tr>${m.critical_high_items.length>0?`<tr><td style="background:#fff;padding:20px 28px;border-top:1px solid #e5e7eb"><h2 style="margin:0 0 14px;font-size:16px;color:#1a1a2e">Critical & High Priority</h2><table width="100%" style="border-collapse:collapse;border:1px solid #e5e7eb"><thead><tr style="background:#f1f5f9"><th style="padding:8px 10px;text-align:left;font-size:11px;color:#6b7280">Conv ID</th><th style="padding:8px 10px;text-align:left;font-size:11px;color:#6b7280">Agent</th><th style="padding:8px 10px;text-align:left;font-size:11px;color:#6b7280">Category</th><th style="padding:8px 10px;text-align:left;font-size:11px;color:#6b7280">Sev</th><th style="padding:8px 10px;text-align:left;font-size:11px;color:#6b7280">Action</th><th style="padding:8px 10px;text-align:left;font-size:11px;color:#6b7280">Link</th></tr></thead><tbody>${critHighRows}</tbody></table></td></tr>`:'<tr><td></td></tr>'}<tr><td style="background:#fff;padding:20px 28px;border-top:1px solid #e5e7eb"><h2 style="margin:0 0 14px;font-size:16px;color:#1a1a2e">Top Issues</h2><table width="100%" style="border-collapse:collapse;border:1px solid #e5e7eb"><thead><tr style="background:#f1f5f9"><th style="padding:8px 10px;font-size:11px;color:#6b7280">#</th><th style="padding:8px 10px;font-size:11px;color:#6b7280">Category</th><th style="padding:8px 10px;font-size:11px;color:#6b7280">Count</th></tr></thead><tbody>${topRows}</tbody></table></td></tr><tr><td style="background:#fff;padding:20px 28px;border-top:1px solid #e5e7eb"><h2 style="margin:0 0 14px;font-size:16px;color:#1a1a2e">Agent Flags</h2><table width="100%" style="border-collapse:collapse;border:1px solid #e5e7eb"><thead><tr style="background:#f1f5f9"><th style="padding:8px 10px;font-size:11px;color:#6b7280">Agent</th><th style="padding:8px 10px;font-size:11px;color:#6b7280">Avg Score</th><th style="padding:8px 10px;font-size:11px;color:#6b7280">Convos</th></tr></thead><tbody>${flagRows}</tbody></table></td></tr><tr><td style="background:#f1f5f9;padding:16px 28px;border-radius:0 0 8px 8px;border-top:1px solid #e5e7eb"><p style="margin:0;font-size:11px;color:#9ca3af;text-align:center">Generated by Chat QA System • ${m.generated_at} • AI analysis — for human review</p></td></tr></table></td></tr></table></body></html>`;
const subject = `[QA Report] ${m.date} — ${m.total_analyzed} convos, ${m.satisfaction_rate}% satisfaction${m.critical_count>0?`, ${m.critical_count} CRITICAL`:''}`;
return [{ json: { subject, html_body: html, plain_text: `Daily QA Report ${m.date}: ${m.total_analyzed} conversations, ${m.satisfaction_rate}% satisfaction, ${m.critical_count} critical, ${m.high_count} high`, metrics: m } }];

const m = $('Compile Metrics').first().json;
const satEmoji = m.satisfaction_rate >= 80 ? ':white_check_mark:' : m.satisfaction_rate >= 60 ? ':warning:' : ':red_circle:';
const topIssuesText = m.top_issues.slice(0,5).map((i,idx) => `${idx+1}. ${i.category}: *${i.count}*`).join('\n');
const agentFlagsText = m.agent_flags.length > 0 ? m.agent_flags.map(a => `• ${a.agent_name}: avg *${a.avg_score}*`).join('\n') : '_None today_';
const critHighText = m.critical_high_items.length > 0 ? m.critical_high_items.slice(0,5).map(i => `• [${i.severity}] ${i.issue_category} — ${i.agent_name} | <${i.intercom_link}|View>`).join('\n') : '_None today_';
const blocks = [{ type: 'header', text: { type: 'plain_text', text: `:bar_chart: Daily QA Report — ${m.date}`, emoji: true } }, { type: 'section', fields: [{ type: 'mrkdwn', text: `*Total:* ${m.total_analyzed}` }, { type: 'mrkdwn', text: `${satEmoji} *Satisfaction:* ${m.satisfaction_rate}%` }, { type: 'mrkdwn', text: `:rotating_light: *Critical:* ${m.critical_count}` }, { type: 'mrkdwn', text: `*High/Med/Low:* ${m.high_count}/${m.medium_count}/${m.low_count}` }] }, { type: 'divider' }, { type: 'section', text: { type: 'mrkdwn', text: `*Critical & High:*\n${critHighText}` } }, { type: 'section', fields: [{ type: 'mrkdwn', text: `*Top Issues:*\n${topIssuesText}` }, { type: 'mrkdwn', text: `*Agent Flags:*\n${agentFlagsText}` }] }];
if (m.pending_analysis_count > 0) { blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `:warning: *${m.pending_analysis_count} conversations still pending analysis* — report may be incomplete.` } }); }
return [{ json: { blocks, text: `QA Report ${m.date}: ${m.total_analyzed} convos, ${m.satisfaction_rate}% satisfaction` } }];
